/**
 * Trim-Split Engine — Pure functions for timeline clip editing operations.
 *
 * Handles: trim (in/out point adjustment), split (divide clip at time),
 * merge (combine adjacent clips), reorder, and audio synchronisation
 * after edits.
 *
 * All functions are pure — no side-effects, no stores, no DOM.
 */

// Types
export interface ClipSegment {
  readonly id: string;
  startTime: number;       // ms, position on timeline
  duration: number;        // ms, visible duration
  inPoint: number;         // ms, offset into source media
  outPoint: number;        // ms, end offset into source media
  trackId: string;
  sourceDuration: number;  // ms, original source duration
  audioUrl?: string;
  name?: string;
}

export interface SplitResult {
  before: ClipSegment;
  after: ClipSegment;
}

export type TrimEdge = 'in' | 'out';

export interface AudioSyncInfo {
  audioOffset: number;     // ms, offset into original audio
  audioDuration: number;   // ms
  needsRegeneration: boolean;
}

export interface SnapCandidate {
  time: number;
  label: string;
}

// Constants
export const MIN_CLIP_DURATION = 100;  // ms
export const SNAP_THRESHOLD_PX = 8;
export const TRIM_HANDLE_WIDTH = 6;    // px

// Validation
export function isTimeInsideClip(clip: ClipSegment, time: number): boolean {
  return time > clip.startTime && time < clip.startTime + clip.duration;
}

export function clampValue(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

export function validateClip(clip: ClipSegment): string[] {
  const errors: string[] = [];
  if (clip.duration < MIN_CLIP_DURATION)
    errors.push(`Duration ${clip.duration}ms is below minimum ${MIN_CLIP_DURATION}ms`);
  if (clip.inPoint < 0)
    errors.push(`inPoint (${clip.inPoint}) must be >= 0`);
  if (clip.outPoint <= clip.inPoint)
    errors.push(`outPoint (${clip.outPoint}) must be > inPoint (${clip.inPoint})`);
  if (clip.outPoint > clip.sourceDuration)
    errors.push(`outPoint (${clip.outPoint}) exceeds sourceDuration (${clip.sourceDuration})`);
  if (clip.startTime < 0)
    errors.push(`startTime (${clip.startTime}) must be >= 0`);
  return errors;
}

// Trim
export function computeTrim(clip: ClipSegment, edge: TrimEdge, deltaMs: number): ClipSegment | null {
  if (edge === 'in') {
    const newInPoint = clampValue(clip.inPoint + deltaMs, 0, clip.outPoint - MIN_CLIP_DURATION);
    const inDelta = newInPoint - clip.inPoint;
    const newStartTime = clip.startTime + inDelta;
    const newDuration = clip.duration - inDelta;
    if (newDuration < MIN_CLIP_DURATION) return null;
    return { ...clip, inPoint: newInPoint, startTime: newStartTime, duration: newDuration };
  }
  // edge === 'out'
  const newOutPoint = clampValue(clip.outPoint + deltaMs, clip.inPoint + MIN_CLIP_DURATION, clip.sourceDuration);
  const newDuration = newOutPoint - clip.inPoint;
  if (newDuration < MIN_CLIP_DURATION) return null;
  return { ...clip, outPoint: newOutPoint, duration: newDuration };
}

export function applyTrim(clip: ClipSegment, edge: TrimEdge, deltaMs: number): ClipSegment | null {
  const result = computeTrim(clip, edge, deltaMs);
  if (!result) return null;
  return validateClip(result).length === 0 ? result : null;
}

// Split
export function splitClipAtTime(clip: ClipSegment, time: number, idA: string, idB: string): SplitResult | null {
  if (!isTimeInsideClip(clip, time)) return null;
  const localSplitOffset = time - clip.startTime;
  if (localSplitOffset < MIN_CLIP_DURATION) return null;
  if (clip.duration - localSplitOffset < MIN_CLIP_DURATION) return null;

  const before: ClipSegment = {
    ...clip, id: idA, duration: localSplitOffset,
    outPoint: clip.inPoint + localSplitOffset,
  };
  const after: ClipSegment = {
    ...clip, id: idB, name: clip.name ? `${clip.name} (Split)` : undefined,
    startTime: time, duration: clip.duration - localSplitOffset,
    inPoint: clip.inPoint + localSplitOffset,
  };
  return { before, after };
}

// Merge
export function mergeClips(a: ClipSegment, b: ClipSegment): ClipSegment | null {
  if (a.trackId !== b.trackId) return null;
  const [first, second] = a.startTime <= b.startTime ? [a, b] : [b, a];
  const gap = second.startTime - (first.startTime + first.duration);
  if (Math.abs(gap) > 1) return null;
  if (first.audioUrl !== second.audioUrl) return null;
  return {
    ...first,
    duration: first.duration + second.duration,
    outPoint: first.inPoint + first.duration + second.duration,
  };
}

// Reorder
export function reorderClipIds(ids: readonly string[], fromIndex: number, toIndex: number): string[] {
  if (fromIndex === toIndex) return [...ids];
  if (fromIndex < 0 || fromIndex >= ids.length) return [...ids];
  if (toIndex < 0 || toIndex >= ids.length) return [...ids];
  const result = [...ids];
  const [moved] = result.splice(fromIndex, 1);
  result.splice(toIndex, 0, moved);
  return result;
}

export function recalculateStartTimes(clips: readonly ClipSegment[], offset = 0): ClipSegment[] {
  let cursor = offset;
  return clips.map((c) => {
    const updated: ClipSegment = { ...c, startTime: cursor };
    cursor += c.duration;
    return updated;
  });
}

// Audio sync
export function computeAudioSync(clip: ClipSegment): AudioSyncInfo {
  if (!clip.audioUrl) {
    return { audioOffset: 0, audioDuration: clip.duration, needsRegeneration: false };
  }
  const audioOffset = clip.inPoint;
  const audioDuration = clip.outPoint - clip.inPoint;
  const needsRegeneration = audioOffset > 0;
  return { audioOffset, audioDuration, needsRegeneration };
}

export function computeSplitAudioSync(splitResult: SplitResult): { before: AudioSyncInfo; after: AudioSyncInfo } {
  return {
    before: computeAudioSync(splitResult.before),
    after: computeAudioSync(splitResult.after),
  };
}

// Snap helpers
export function findSnapPoint(
  proposedTime: number,
  candidates: readonly SnapCandidate[],
  pixelsPerSecond: number,
  thresholdPx: number = SNAP_THRESHOLD_PX,
): SnapCandidate | null {
  const thresholdMs = (thresholdPx / pixelsPerSecond) * 1000;
  let best: SnapCandidate | null = null;
  let bestDist = Infinity;
  for (const c of candidates) {
    const dist = Math.abs(c.time - proposedTime);
    if (dist < thresholdMs && dist < bestDist) {
      bestDist = dist;
      best = c;
    }
  }
  return best;
}

export function buildSnapCandidates(clips: readonly ClipSegment[], playheadTime?: number): SnapCandidate[] {
  const candidates: SnapCandidate[] = [];
  for (const c of clips) {
    candidates.push({ time: c.startTime, label: `${c.name ?? c.id} start` });
    candidates.push({ time: c.startTime + c.duration, label: `${c.name ?? c.id} end` });
  }
  if (playheadTime !== undefined) candidates.push({ time: playheadTime, label: 'playhead' });
  candidates.push({ time: 0, label: 'origin' });
  return candidates;
}

// Pixel ↔ Time conversion
export function timeToPx(timeMs: number, pixelsPerSecond: number): number {
  return (timeMs / 1000) * pixelsPerSecond;
}

export function pxToTime(px: number, pixelsPerSecond: number): number {
  return (px / pixelsPerSecond) * 1000;
}

export function clipToPixelRect(
  clip: ClipSegment,
  pixelsPerSecond: number,
  trackHeight: number,
): { x: number; width: number; height: number } {
  return {
    x: timeToPx(clip.startTime, pixelsPerSecond),
    width: timeToPx(clip.duration, pixelsPerSecond),
    height: trackHeight,
  };
}

// Split marker
export function splitMarkerPosition(
  clip: ClipSegment,
  playheadTime: number,
  pixelsPerSecond: number,
): number | null {
  if (!isTimeInsideClip(clip, playheadTime)) return null;
  const localTime = playheadTime - clip.startTime;
  return timeToPx(localTime, pixelsPerSecond);
}

// Batch operations
export function removeAndClose(clips: readonly ClipSegment[], clipId: string): ClipSegment[] {
  const filtered = clips.filter((c) => c.id !== clipId);
  return recalculateStartTimes(filtered, filtered[0]?.startTime ?? 0);
}

export function insertAndRecalculate(
  clips: readonly ClipSegment[],
  newClip: ClipSegment,
  index: number,
): ClipSegment[] {
  const result = [...clips];
  const safeIndex = clampValue(index, 0, result.length);
  result.splice(safeIndex, 0, newClip);
  return recalculateStartTimes(result, result[0]?.startTime ?? 0);
}

export function totalDuration(clips: readonly ClipSegment[]): number {
  if (clips.length === 0) return 0;
  const last = clips[clips.length - 1];
  return last.startTime + last.duration;
}
